import{_ as o,o as c,c as d,as as p}from"./chunks/framework.Dt0DMeWU.js";const x=JSON.parse('{"title":"第三章 Linux 的目录结构","description":"","frontmatter":{},"headers":[],"relativePath":"backend/Linux/03 第三章 Linux的目录结构.md","filePath":"backend/Linux/03 第三章 Linux的目录结构.md","lastUpdated":1775485159000}'),n={name:"backend/Linux/03 第三章 Linux的目录结构.md"};function i(a,e,t,s,r,u){return c(),d("div",null,[...e[0]||(e[0]=[p('<h1 id="第三章-linux-的目录结构" tabindex="-1">第三章 <code>Linux</code> 的目录结构 <a class="header-anchor" href="#第三章-linux-的目录结构" aria-label="Permalink to &quot;第三章 `Linux` 的目录结构&quot;">​</a></h1><h2 id="学习目标" tabindex="-1">学习目标 <a class="header-anchor" href="#学习目标" aria-label="Permalink to &quot;学习目标&quot;">​</a></h2><p><code>1</code> 熟悉 <code>Linux</code> 目录的组织习惯!</p><p><code>2</code> 熟悉一些 <code>Linux</code> 的常见目录及作用</p><h2 id="第一节-linux-中的常见目录" tabindex="-1">第一节 <code>Linux</code> 中的常见目录 <a class="header-anchor" href="#第一节-linux-中的常见目录" aria-label="Permalink to &quot;第一节 `Linux` 中的常见目录&quot;">​</a></h2><blockquote><p><code>Linux</code> 常见的目录结构，不同版本的 <code>Linux</code> 目录结构可能略有不同</p></blockquote><p><img src="https://img.xbin.cn/blog/m1_SOazlwnZeT.png" alt=""></p><blockquote><p><code>Centos7</code> 的文件目录结构</p></blockquote><p><img src="https://img.xbin.cn/blog/m3_dsz1PMmPxe.png" alt=""></p><blockquote><p><code>Linux</code> 根目录下的常见目录及作用</p></blockquote><p><code>1</code>. /<code>bin</code>：★(/<code>usr</code>/<code>bin</code>,/<code>usr</code>/<code>local</code>/<code>bin</code>)</p><p>是 <code>Binary</code> 的缩写, 这个目录存放着最经常使用的命令,<code>Linux</code> 默认的环境变量已经包含该路径,所以可以直接使用该路径下的指令如 <code>cd</code> 指令 </p><p>可以通过 <code>echo</code> $<code>PATH</code> 查看系统环境变量来看是否包含了该目录</p><p><code>2</code>. /<code>sbin</code>：(/<code>usr</code>/<code>sbin</code>, /<code>usr</code>/<code>local</code>/<code>sbin</code>)</p><p><code>s</code> 就是 <code>Super User</code> 的意思，这里存放的是系统管理员使用的系统管理程序。</p><p>以上目录，任何命令在任意目录下都可执行命令</p><p><code>3</code>. /<code>home</code>：★</p><p>存放普通用户的主目录，在 <code>Linux</code> 中每个用户都有一个自己的目录，一般该目录名是以用户的账号命名的。</p><p><code>4</code>. /<code>root</code>：★</p><p>该目录为系统管理员，也称作超级权限者的用户主目录。</p><p><code>5</code>. /<code>lib</code>：</p><p>系统开机所需要最基本的动态连接共享库，其作用类似于 <code>Windows</code> 里的 <code>DLL</code> 文件。几乎所有的应用程序都需要用到这些共享库。</p><p><code>6</code>. /<code>lost</code>+<code>found</code>：</p><p>这个目录一般情况下是空的，当系统非法关机后，这里就存放了一些文件。</p><p><code>7</code>. /<code>etc</code>：★</p><p>所有的系统管理所需要的配置文件和子目录。<code>my.cnf</code></p><p><code>8</code>. /<code>usr</code>：★ </p><p>这是一个非常重要的目录，用户的很多应用程序和文件都放在这个目录下，类似与 <code>windows</code> 下的 <code>program files</code> 目录。</p><p><code>9</code>. /<code>boot</code>：★</p><p>这里存放的是启动 <code>Linux</code> 时使用的一些核心文件，包括一些连接文件以及镜像文件，自己的安装别放这里 </p><p><code>10</code>. /<code>proc</code>：</p><p>这个目录是一个虚拟的目录，它是系统内存的映射，我们可以通过直接访问这个目录来获取系统信息。</p><p><code>11</code>. /<code>srv</code>：</p><p><code>service</code> 缩写，该目录存放一些服务启动之后需要提取的数据。</p><p><code>12</code>. /<code>sys</code>： </p><p>这是 <code>linux2.6</code> 内核的一个很大的变化。该目录下安装了 <code>2.6</code> 内核中新出现的一个文件系统 <code>sysfs</code> 。（内核）</p><p><code>13</code>. /<code>tmp</code>：</p><p>这个目录是用来存放一些临时文件的。</p><p><code>14</code>. /<code>dev</code>：★</p><p><code>Device</code>(设备)的缩写,类似 <code>windows</code> 的设备管理器，把所有的硬件用文件的形式存储。 </p><p><code>15</code>. /<code>media</code>：★</p><p><code>linux</code> 系统会自动识别一些设备，例如 <code>U</code> 盘、光驱等等，当识别后，<code>linux</code> 会把识别的设备挂载到这个目录下。<code>CentOS6</code> 就在/<code>media</code> 下,<code>CentOS7</code> 换目录了/</p><p><img src="https://img.xbin.cn/blog/m3_3xSqMZd5DF.png" alt=""></p><p><code>16</code>. /<code>mnt</code>：★</p><p>系统提供该目录是为了让用户临时挂载别的文件系统的，我们可以将光驱挂载在/<code>mnt</code>/上，然后进入该目录就可以查看光驱里的内容了。</p><p><code>17</code>. /<code>opt</code>：★</p><p>这是给主机额外安装软件所摆放的目录。</p><p>比如你安装 <code>JDK</code>、<code>Tomcat</code> 则就可以放到这个目录下。默认是空的。</p><p><code>18</code>. /<code>usr</code>/<code>local</code>: ★</p><p>这是另一个给主机额外安装软件所摆放的目录.一般是通过编译源码方式安装的程序。</p><p><code>19</code>. /<code>var</code>：★</p><p>这个目录中存放着在不断扩充着的东西，我们习惯将那些经常被修改的目录放在这个目录下。包括各种日志文件。</p>',52)])])}const _=o(n,[["render",i]]);export{x as __pageData,_ as default};
